parameters.jsCode:
// Enrich critical issues with additional context
const item = $input.item.json;

// Generate executive summary
const executiveSummary = `CRITICAL ALERT: ${item.risk_type || 'Unknown risk'} detected in ${item.workflow_state || 'unknown state'}. Severity: ${item.severity}. Priority: ${item.priority}/10. Confidence: ${(item.confidence_score * 100).toFixed(1)}%. Immediate attention required from ${item.responsible_team || 'engineering team'}.`;

// Generate immediate actions based on observed issues
const immediateActions = [];
if (item.observed_issues && Array.isArray(item.observed_issues)) {
  item.observed_issues.forEach((issue, index) => {
    immediateActions.push(`Action ${index + 1}: Investigate and address - ${issue}`);
  });
}

// Add recommended action if available
if (item.recommended_action) {
  immediateActions.push(`Primary Recommendation: ${item.recommended_action}`);
}

// If no specific actions, add default critical response
if (immediateActions.length === 0) {
  immediateActions.push('Immediate investigation required');
  immediateActions.push('Notify responsible team and stakeholders');
  immediateActions.push('Implement emergency protocols');
}

// Return enriched item
return {
  ...item,
  escalation_timestamp: new Date().toISOString(),
  critical_alert_sent: true,
  executive_summary: executiveSummary,
  immediate_actions_required: immediateActions
};

// Calculate composite risk score based on severity, priority, confidence_score, and predicted_impact

// Parse severity to numeric value
const severityMap = {
  'critical': 4,
  'high': 3,
  'medium': 2,
  'low': 1
};

const severity = $input.item.json.severity || 'low';
const severityValue = severityMap[severity.toLowerCase()] || 1;

const priority = $input.item.json.priority || 1;
const confidenceScore = $input.item.json.confidence_score || 0.5;

// Calculate composite risk score
const compositeRiskScore = severityValue * priority * confidenceScore;

// Categorize risk
let riskCategory = 'low';
if (compositeRiskScore >= 10) {
  riskCategory = 'critical';
} else if (compositeRiskScore >= 6) {
  riskCategory = 'high';
} else if (compositeRiskScore >= 3) {
  riskCategory = 'medium';
}

// Determine if escalation is required
const escalationRequired = compositeRiskScore >= 6 || severity === 'critical';

// Return enriched data
return {
  ...$input.item.json,
  composite_risk_score: Math.round(compositeRiskScore * 100) / 100,
  risk_category: riskCategory,
  escalation_required: escalationRequired
};
